import re
def extract_date(s):
    if pd.isna(s): return pd.NaT
    s = str(s).strip()
    match = re.search(r'(\d{1,2})[-/](\d{1,2})[-/](\d{4})', s)
    if match:
        d, m, y = match.groups()
        return pd.to_datetime(f"{y}-{m}-{d}")
    match = re.search(r'(\d{4})-(\d{1,2})-(\d{1,2})', s)
    if match:
        y, m, d = match.groups()
        return pd.to_datetime(f"{y}-{m}-{d}")
    return pd.NaT

df['parsed_date'] = df['ngày_công_bố'].apply(extract_date)
print(df['parsed_date'].isna().sum())
print(df[df['parsed_date'].isna()]['ngày_công_bố'])
